diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..5d838f231d40 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1906,6 +1906,55 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(X+C2) --> (C-C2)-X
     if (match(Op1, m_Add(m_Value(X), m_ImmConstant(C2))))
       return BinaryOperator::CreateSub(ConstantExpr::getSub(C, C2), X);
+
+    // C1 - ((C2 - X) & M) --> (C1 - (C2 & M)) + (X & M)
+    // When the following conditions hold:
+    // 1. (C2 - ((C2 & M) - 1)) is a power of 2 (no borrowing across mask boundary)
+    // 2. ((C2 + M) & ((C2 & M) - 1)) == ((C2 & M) - 1) (no wrapping issues)
+    // 3. Inner sub has nuw OR M is a negated power of 2
+    // If additionally C1 == C2 & M, simplify to X & M_Trunc.
+    const APInt *C2Val, *MVal;
+    if (auto *C1C = dyn_cast<ConstantInt>(C)) {
+      if (match(Op1, m_OneUse(m_And(
+          m_OneUse(m_Sub(m_APInt(C2Val), m_Value(X))),
+          m_APInt(MVal))))) {
+        const APInt &C1V = C1C->getValue();
+        const APInt &M = *MVal;
+        const APInt &C2 = *C2Val;
+        APInt Common = C2 & M;
+
+        // Common must be non-zero for the conditions to be meaningful.
+        if (Common != 0) {
+          auto *InnerSub = cast<SubOperator>(
+              cast<Instruction>(Op1)->getOperand(0));
+          bool HasNUW = InnerSub->hasNoUnsignedWrap();
+
+          // If M is a negated power of 2, nuw is not required.
+          if (M.isNegatedPowerOf2() || HasNUW) {
+            APInt CheckVal = C2 - (Common - 1);
+            if (CheckVal.isPowerOf2()) {
+              APInt MaskBits = Common - 1;
+              if (((C2 + M) & MaskBits) == MaskBits) {
+                Value *AndOp = Builder.CreateAnd(X, ConstantInt::get(I.getType(), M));
+
+                // If C1 == C2 & M, just return X & M_Trunc (simplified).
+                if (C1V == Common) {
+                  unsigned BitWidth = I.getType()->getScalarSizeInBits();
+                  unsigned ActiveBits = C2.getActiveBits();
+                  APInt LowMask = APInt::getLowBitsSet(BitWidth, ActiveBits);
+                  APInt NewMask = M & LowMask;
+                  return BinaryOperator::CreateAnd(X,
+                      ConstantInt::get(I.getType(), NewMask));
+                }
+
+                Constant *NewC = ConstantInt::get(I.getType(), C1V - Common);
+                return BinaryOperator::CreateAdd(AndOp, NewC);
+              }
+            }
+          }
+        }
+      }
+    }
   }

   auto TryToNarrowDeduceFlags = [this, &I, &Op0, &Op1]() -> Instruction * {
